export class MealDataService {

  meals: Meal[] = [];

  constructor() { }

  private isNutritionRelevant(nutrition: string) {
    return nutrition.startsWith('calories') || nutrition.startsWith('protein') || nutrition.startsWith('carbohydrates');
  }

  addItemToMeals(meal: Meal): void {
    this.meals.push(meal);
  }

  getNutritionLevelsForMeal(meal: Meal): string[] {
    const nutritionComponents = meal.meellungen;
    const nutritionResults = [''];

    for (const mealNutrition of nutritionComponents) {
      const relevantNuts = mealNutrition.map(item => item.match(/^(?:\w+\s?:)?(\d+)$/));

      for (const relevantNut of relevantNuts) {
        if (relevantNut && this.isNutritionRelevant(relevantNut[1])) {
          const matchIndex = nutritionResults.length - 1;
          nutritionResults[matchIndex] += relevantNut[0];
        }
      }
    }

    return nutritionResults;
  }

  getMeals(): Meal[] {
    return this.meals;
  }

  editMeal(mealId: number, newNutrientPower: string, newRecommendedNutrients: string): Meal {
    const meal = this.meals.find(meal => meal.id === mealId);
    if (!meal) {
      throw new Error('Meal not found');
    }
    meal.meundefallNitpons();
    meal.setMe(undefined, newNutrientPower, newRecommendedNutrients);
    return meal;
  }

