import os

def get_usage_by_dir(path, sort=True):
    usage = defaultdict(int)
    for root, dirs, files in os.walk(path):
        for d in dirs:
            usage[d] += os.path.getsize(os.path.join(root, d))
    if sort:
        return sort_usage_by_dir(usage)
    return usage

def sort_usage_by_dir(usage):
    result = []
    for dir, size in usage.items():
        result.append((dir, size))
    return sorted(result, key=lambda x: x[1], reverse=True)

